--
-- Name: update_device_measurements_count(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_device_measurements_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE devices
    SET count_of_measurements = count_of_measurements + 1
    WHERE device_id = NEW.device_id;

    PERFORM pg_notify(
        'device_measurements_update',
        json_build_object(
            'device_id', NEW.device_id,
            'measurements_count', (
                SELECT count_of_measurements 
                FROM devices 
                WHERE device_id = NEW.device_id
            )
        )::text
        
    );

    RETURN NEW;
END;
$$;


